// 转换方法
function buildTree(array, id_key, parentId_key){
  let result = []
  if (!Array.isArray(array)) {
    return result
  }
  array.forEach(item => {
    delete item.children;
  });
  let map = {};
  array.forEach(item => {
    map[item[id_key]] = item;
  });
  array.forEach(item => {
    let parent = map[item[parentId_key]];
    if (parent) {
      (parent.children || (parent.children = [])).push(item);
    } else {
      result.push(item);
    }
  });
  return result;
}

